mapper.sql:
WHERE 1 = 1
AND s.user_id = #{request.userId}
AND s.skill_id = #{request.skillId}
AND s.status = #{request.status}
AND DATE(s.create_time) >= #{request.startDate}
AND DATE(s.create_time) <= #{request.endDate}

    AND (
        s.session_title LIKE CONCAT('%', #{request.keywords}, '%')
        OR sk.skill_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR kb.base_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR usr.real_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR usr.username LIKE CONCAT('%', #{request.keywords}, '%')
    )

WHERE 1 = 1
AND s.user_id = #{request.userId}
AND s.skill_id = #{request.skillId}
AND s.status = #{request.status}

    AND (
        s.session_title LIKE CONCAT('%', #{request.keywords}, '%')
        OR sk.skill_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR kb.base_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR usr.real_name LIKE CONCAT('%', #{request.keywords}, '%')
        OR usr.username LIKE CONCAT('%', #{request.keywords}, '%')
    )

AND EXTRACT(YEAR FROM s.create_time) = #{request.year}

mapper.select:
SELECT TO_CHAR(DATE(s.create_time), 'YYYY-MM-DD') AS label, COUNT(1) AS value FROM ai_agent_session s LEFT JOIN sys_user usr ON usr.id = s.user_id LEFT JOIN ai_skill sk ON sk.id = s.skill_id LEFT JOIN ai_knowledge_base kb ON kb.id = s.base_id WHERE 1 = 1 AND s.user_id = #{request.userId} AND s.skill_id = #{request.skillId} AND s.status = #{request.status} AND DATE(s.create_time) >= #{request.startDate} AND DATE(s.create_time) <= #{request.endDate}
AND ( s.session_title LIKE CONCAT('%', #{request.keywords}, '%') OR sk.skill_name LIKE CONCAT('%', #{request.keywords}, '%') OR kb.base_name LIKE CONCAT('%', #{request.keywords}, '%') OR usr.real_name LIKE CONCAT('%', #{request.keywords}, '%') OR usr.username LIKE CONCAT('%', #{request.keywords}, '%') )
GROUP BY DATE(s.create_time) ORDER BY DATE(s.create_time) ASC
